    def test_v7_candidate_library_uses_geometry_first_decoupled_retrieval(self) -> None:
        from research.strict_eval_search_space import strict_v7_candidate_library

        candidates = strict_v7_candidate_library()
        names = {candidate.name for candidate in candidates}
        intervention_types = {candidate.intervention_type for candidate in candidates}

        self.assertEqual(
            names,
            {
                "v7 geometry-first control",
                "v7 geometry-first + stronger queue",
                "v7 geometry-first + equivalence proxies",
                "v7 geometry-first + paraphrase views",
                "v7 geometry-first + late abstention",
            },
        )
        self.assertEqual(intervention_types, {"geometry_first_decoupled_retrieval"})
        control = next(candidate for candidate in candidates if candidate.name == "v7 geometry-first control")
        self.assertTrue(control.phase4_updates["use_query_multiview"])
        self.assertTrue(control.phase4_updates["use_momentum_queue"])
        self.assertEqual(control.phase4_updates["ood_weight"], 0.0)
        self.assertEqual(control.phase4_updates["clf_weight"], 0.0)
        proxy_variant = next(candidate for candidate in candidates if candidate.name == "v7 geometry-first + equivalence proxies")
        self.assertTrue(proxy_variant.phase4_updates["use_equivalence_class_retrieval"])
        self.assertTrue(proxy_variant.phase4_updates["use_equivalence_prototypes"])
        self.assertAlmostEqual(proxy_variant.phase4_updates["prototype_repulsion_weight"], 0.05)

