    def test_runner_uses_v39_base_model_path_without_training(self) -> None:
        from unittest.mock import patch

        from experiments.run_strict_eval_autoresearch import run_candidate
        from research.strict_eval_search_space import strict_v39_candidate_library

        candidate = next(candidate for candidate in strict_v39_candidate_library() if candidate.name == "v39 consensus verifier control")
        fake_summary = {"strict_status": "❌ FAIL", "avg_known_exact_similarity": 0.4}
        with tempfile.TemporaryDirectory() as tmpdir:
            with patch("experiments.run_strict_eval_autoresearch.artifacts_for_mode", return_value=Path(tmpdir)), \
                 patch("experiments.run_strict_eval_autoresearch.ensure_results_header"), \
                 patch("experiments.run_strict_eval_autoresearch.append_result"), \
                 patch("experiments.run_strict_eval_autoresearch._parse_summary_blob", return_value=fake_summary), \
                 patch("experiments.run_strict_eval_autoresearch.subprocess.call") as train_call, \
                 patch("experiments.run_strict_eval_autoresearch.subprocess.check_output", return_value='{"strict_status":"❌ FAIL","avg_known_exact_similarity":0.4}'), \
                 patch("experiments.run_strict_eval_autoresearch.shutil.copy2") as copy_mock:
                summary = run_candidate(candidate, seed=777, mode="v39")
                self.assertEqual(summary, fake_summary)
                train_call.assert_not_called()
                copy_mock.assert_called_once()

