    def test_detect_stall_flags_adaptive_plateau(self) -> None:
        from experiments.run_strict_eval_autoresearch import default_search_state, detect_stall

        state = default_search_state(mode="v33")
        state["history"] = [
            {
                "candidate_name": f"adaptive recovery cycle {idx}",
                "run_id": f"adaptive-recovery-cycle-{idx}-seed{600 + idx}",
                "seed": 600 + idx,
                "score": -4.30 + (0.01 if idx == 4 else 0.0),
                "strict_status": "❌ FAIL",
                "family": "adaptive_margin",
                "primary_failure_mode": "calibration_bound_signal" if idx % 2 else "margin_starved_signal",
                "flags": ["query_collapse", "code_low_rank", "ood_overconfident"],
                "phase4_updates": {},
            }
            for idx in range(1, 17)
        ]

        stall = detect_stall(state, window=8, min_runs=12, min_improvement=0.05)
        self.assertIsNotNone(stall)
        assert stall is not None
        self.assertEqual(stall["reason"], "adaptive_plateau")
        self.assertIn("query_collapse", stall["dominant_flags"])
        self.assertIn("code_low_rank", stall["dominant_flags"])

