    def test_write_stop_notice_includes_recommended_followup(self) -> None:
        import json
        import tempfile
        from pathlib import Path
        from unittest.mock import patch

        from experiments.run_strict_eval_autoresearch import _write_stop_notice, default_search_state

        state = default_search_state(mode="v33")
        state["incumbent_name"] = "v33 proxy-anchor discrimination + delayed boundary"
        state["incumbent_score"] = -4.4315
        state["history"] = [
            {
                "candidate_name": "v33 proxy-anchor discrimination + delayed boundary",
                "run_id": "v33-proxy-anchor-discrimination-delayed-boundary-seed508",
                "seed": 508,
                "score": -4.4315,
                "strict_status": "❌ FAIL",
                "family": "proxy_anchor_discrimination_retrieval",
                "primary_failure_mode": "calibration_bound_signal",
                "flags": ["query_collapse", "code_low_rank", "ood_overconfident"],
                "phase4_updates": {},
            },
        ]

        with tempfile.TemporaryDirectory() as tmpdir:
            root = Path(tmpdir)
            with patch("experiments.run_strict_eval_autoresearch.ROOT", root):
                payload = _write_stop_notice(state, "adaptive_plateau", {"dominant_flags": ["query_collapse"]})
                self.assertEqual(payload["recommended_followup"]["next_mode"], "v34")
                stop_path = root / "artifacts" / "strict_eval_autoresearch_v33" / "stop_notice.json"
                saved = json.loads(stop_path.read_text())
                self.assertEqual(saved["recommended_followup"]["next_mode"], "v34")

