    def test_auto_followup_launches_child_mode_when_recommended(self) -> None:
        import tempfile
        from pathlib import Path
        from unittest.mock import patch

        from experiments.run_strict_eval_autoresearch import _maybe_chain_followup

        stop_notice = {
            "recommended_followup": {
                "next_mode": "v35",
            }
        }

        with tempfile.TemporaryDirectory() as tmpdir:
            root = Path(tmpdir)
            with patch("experiments.run_strict_eval_autoresearch.ROOT", root), \
                 patch("experiments.run_strict_eval_autoresearch.PYTHON", root / "python"), \
                 patch("experiments.run_strict_eval_autoresearch.subprocess.call", return_value=0) as call_mock:
                rc = _maybe_chain_followup("v34", stop_notice)
                self.assertEqual(rc, 0)
                argv = call_mock.call_args.args[0]
                self.assertIn("--mode", argv)
                self.assertIn("v35", argv)

