    def test_v62_candidate_library_uses_frontier_replay_branch_recombination_retrieval(self) -> None:
        from research.strict_eval_search_space import strict_v62_candidate_library

        candidates = strict_v62_candidate_library()
        names = {candidate.name for candidate in candidates}
        intervention_types = {candidate.intervention_type for candidate in candidates}
        self.assertEqual(
            names,
            {
                "v62 frontier-replay control",
                "v62 frontier-replay + tiny late boundary",
                "v62 frontier-replay + light queue",
                "v62 frontier-replay + local equivalence anchors",
                "v62 frontier-replay + light multiview helper",
            },
        )
        self.assertEqual(intervention_types, {"frontier_replay_branch_recombination_retrieval"})
        control = next(candidate for candidate in candidates if candidate.name == "v62 frontier-replay control")
        self.assertTrue(str(control.warm_start_model_path).endswith("artifacts/strict_eval_autoresearch_v50/adaptive-recovery-cycle-18-seed524/model.pt"))
        self.assertFalse(control.phase4_updates["freeze_backbone"])
        self.assertFalse(control.phase4_updates["reset_query_head_on_resume"])
        self.assertAlmostEqual(control.phase4_updates["rank_reg_weight"], 0.05)
        self.assertAlmostEqual(control.phase4_updates["retrieval_margin_embedding_weight"], 0.60)
        self.assertAlmostEqual(control.phase4_updates["ranking_margin_weight"], 0.15)
        self.assertEqual(control.phase4_updates["production_mode"], False)
        self.assertEqual(control.phase4_updates["production_steps"], 0)
        self.assertEqual(control.phase4_updates["production_phase4_repeats"], 0)
        boundary = next(candidate for candidate in candidates if candidate.name == "v62 frontier-replay + tiny late boundary")
        self.assertAlmostEqual(boundary.phase4_updates["epistemic_boundary_weight"], 0.03)
        queue = next(candidate for candidate in candidates if candidate.name == "v62 frontier-replay + light queue")
        self.assertTrue(queue.phase4_updates["use_momentum_queue"])
        anchors = next(candidate for candidate in candidates if candidate.name == "v62 frontier-replay + local equivalence anchors")
        self.assertTrue(anchors.phase4_updates["use_equivalence_prototypes"])
        self.assertEqual(anchors.phase4_updates["prototype_target"], "equivalence")
        multiview = next(candidate for candidate in candidates if candidate.name == "v62 frontier-replay + light multiview helper")
        self.assertTrue(multiview.phase4_updates["use_query_multiview"])
        self.assertAlmostEqual(multiview.phase4_updates["query_multiview_weight"], 0.10)

    def test_runner_materializes_v62_frontier_replay_config(self) -> None:
        from experiments.run_strict_eval_autoresearch import materialize_run_config
        from research.strict_eval_search_space import strict_v62_candidate_library

        candidate = next(candidate for candidate in strict_v62_candidate_library() if candidate.name == "v62 frontier-replay + tiny late boundary")
        with tempfile.TemporaryDirectory() as tmpdir:
            run_dir = Path(tmpdir) / "run-062"
            config_path = materialize_run_config(run_dir, candidate, seed=1912)
            self.assertTrue(config_path.exists())
            config = yaml.safe_load(config_path.read_text())
            self.assertEqual(config["seed"], 1912)
            self.assertEqual(config["profile"], "strict-eval-autoresearch-v4-v62-frontier-replay-tiny-late-boundary-seed1912")
            self.assertAlmostEqual(config["lexical_weight"], 0.65)
            self.assertAlmostEqual(config["confidence_threshold"], 0.44)
            self.assertEqual(config["phase4"]["production_mode"], False)
            self.assertEqual(config["phase4"]["production_steps"], 0)
            self.assertEqual(config["phase4"]["production_phase4_repeats"], 0)
            self.assertFalse(config["phase4"]["freeze_backbone"])
            self.assertFalse(config["phase4"]["reset_query_head_on_resume"])
            self.assertAlmostEqual(config["phase4"]["rank_reg_weight"], 0.05)
            self.assertAlmostEqual(config["phase4"]["retrieval_margin_weight"], 0.20)
            self.assertAlmostEqual(config["phase4"]["epistemic_boundary_weight"], 0.03)
            self.assertTrue(str(candidate.warm_start_model_path).endswith("artifacts/strict_eval_autoresearch_v50/adaptive-recovery-cycle-18-seed524/model.pt"))

