        self.assertAlmostEqual(followup["evidence"]["best_score"], -2.5260471180081376)
        self.assertEqual(followup["evidence"]["best_static_name"], "v62 frontier-replay + light multiview helper")
        self.assertAlmostEqual(followup["evidence"]["best_static_score"], -4.429861645648876)
        self.assertAlmostEqual(followup["evidence"]["light_multiview_score"], -4.429861645648876)
        self.assertIn("v62 frontier-replay control", followup["evidence"]["catastrophic_static_failures"])

