    def test_recommend_followup_mode_moves_v307_to_v308(self) -> None:
        from experiments.run_strict_eval_autoresearch import recommend_followup_mode

        state = {
            "mode": "v307",
            "incumbent_name": "v307 v305-reset thirteen-facets + fourteen facets + slightly milder predictor alignment",
            "incumbent_score": 30.69081890334686,
            "history": [
                {
                    "candidate_name": "v307 v305-reset thirteen-facets control",
                    "score": 24.2187,
                },
                {
                    "candidate_name": "v307 v305-reset thirteen-facets + mild all-stream rank guard",
                    "score": 30.5769,
                },
                {
                    "candidate_name": "v307 v305-reset thirteen-facets + slightly milder predictor alignment",
                    "score": 29.8453,
                },
                {
                    "candidate_name": "v307 v305-reset thirteen-facets + mild all-stream rank guard + slightly milder predictor alignment",
                    "score": 30.4696,
                },
                {
                    "candidate_name": "v307 v305-reset thirteen-facets + fourteen facets + slightly milder predictor alignment",
                    "score": 30.6908,
                },
            ],
        }
        stop_notice = {
            "reason": "no_candidate_available",
            "mode": "v307",
            "completed_runs": len(state["history"]),
            "incumbent_name": state["incumbent_name"],
            "incumbent_score": state["incumbent_score"],
        }
        followup = recommend_followup_mode("v307", state, stop_notice)
        self.assertEqual(followup["next_mode"], "v308")
        self.assertAlmostEqual(followup["evidence"]["control_score"], 24.2187, places=4)
        self.assertAlmostEqual(followup["evidence"]["mild_all_stream_rank_guard_score"], 30.5769, places=4)
        self.assertAlmostEqual(followup["evidence"]["slightly_milder_predictor_alignment_score"], 29.8453, places=4)
        self.assertAlmostEqual(
            followup["evidence"]["mild_all_stream_rank_guard_slightly_milder_predictor_alignment_score"],
            30.4696,
            places=4,
        )
        self.assertAlmostEqual(
            followup["evidence"]["fourteen_facets_slightly_milder_predictor_alignment_score"],
            30.6908,
            places=4,
        )
        self.assertAlmostEqual(followup["evidence"]["v305_frontier_score"], 31.06095204253991, places=6)
        self.assertEqual(
            followup["evidence"]["remaining_strict_failures"],
            [
                "code embedding effective rank is too low",
                "known confidence too low",
                "query embedding effective rank is too low",
            ],
        )

