    def test_recommend_followup_mode_moves_v355_to_v356(self) -> None:
        from experiments.run_strict_eval_autoresearch import default_search_state, recommend_followup_mode

        state = default_search_state(mode="v355")
        state["incumbent_name"] = "v355 v351-reset + taxonomy support-discipline curriculum"
        state["incumbent_score"] = 38.79713395237923
        state["history"] = [
            {"candidate_name": "v355 v351-reset control", "run_id": "a", "seed": 501, "score": 35.65107476562262, "family": "v351_direct_support_discipline_rank_confidence_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v355 v351-reset + taxonomy support-discipline curriculum", "run_id": "b", "seed": 502, "score": 38.79713395237923, "family": "v351_direct_support_discipline_rank_confidence_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v355 v351-reset + taxonomy support-discipline curriculum + deeper hard-negative ladder", "run_id": "c", "seed": 503, "score": 37.27847629785538, "family": "v351_direct_support_discipline_rank_confidence_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v355 v351-reset + taxonomy support-discipline curriculum + mixed query-pred confidence lift", "run_id": "d", "seed": 504, "score": 36.916934194664165, "family": "v351_direct_support_discipline_rank_confidence_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v355 v351-reset + taxonomy support-discipline curriculum + deeper hard-negative ladder + mixed query-pred confidence lift", "run_id": "e", "seed": 505, "score": 37.26480729877949, "family": "v351_direct_support_discipline_rank_confidence_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
        ]
        stop_notice = {"reason": "no_candidate_available", "mode": "v355", "completed_runs": len(state["history"]), "incumbent_name": state["incumbent_name"], "incumbent_score": state["incumbent_score"]}
        followup = recommend_followup_mode("v355", state, stop_notice)
        self.assertEqual(followup["next_mode"], "v356")
        self.assertAlmostEqual(followup["evidence"]["control_score"], 35.65107476562262, places=6)
        self.assertAlmostEqual(followup["evidence"]["taxonomy_support_discipline_curriculum_score"], 38.79713395237923, places=6)
        self.assertAlmostEqual(followup["evidence"]["taxonomy_support_discipline_curriculum_deeper_hard_negative_ladder_score"], 37.27847629785538, places=6)
        self.assertAlmostEqual(followup["evidence"]["taxonomy_support_discipline_curriculum_mixed_query_pred_confidence_lift_score"], 36.916934194664165, places=6)
        self.assertAlmostEqual(followup["evidence"]["taxonomy_support_discipline_curriculum_deeper_hard_negative_ladder_mixed_query_pred_confidence_lift_score"], 37.26480729877949, places=6)
        self.assertAlmostEqual(followup["evidence"]["v351_frontier_score"], 38.85648351659378, places=6)
        self.assertEqual(
            followup["evidence"]["remaining_strict_failures"],
            [
                "direct support retrieval hygiene too low",
                "supported-family abstentions still dominate missed direct hits",
                "code/query effective rank still too low",
            ],
        )

