    def test_recommend_followup_mode_moves_v358_to_v359(self) -> None:
        from experiments.run_strict_eval_autoresearch import default_search_state, recommend_followup_mode

        state = default_search_state(mode="v358")
        # runner looks for "control" suffix, exact match against history entry
        state["incumbent_name"] = "v358 v351-reset + taxonomy support-discipline + live equivalence positives control"
        state["incumbent_score"] = 38.7409
        state["history"] = [
            # Exact candidate names as stored in history (include " control" suffix)
            {"candidate_name": "v358 v351-reset + taxonomy support-discipline + live equivalence positives control", "run_id": "a", "seed": 501, "score": 38.7409, "family": "v351_phase4_live_equivalence_support_discipline_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v358 v351-reset + taxonomy support-discipline + live equivalence positives + support-slate local top-rank", "run_id": "b", "seed": 502, "score": 38.8565, "family": "v351_phase4_live_equivalence_support_discipline_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v358 v351-reset + taxonomy support-discipline + live equivalence positives + support-slate + deeper hard-negative ladder", "run_id": "c", "seed": 503, "score": 38.7409, "family": "v351_phase4_live_equivalence_support_discipline_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v358 v351-reset + taxonomy support-discipline + live equivalence positives + support-slate + localization", "run_id": "d", "seed": 504, "score": 38.7409, "family": "v351_phase4_live_equivalence_support_discipline_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
            {"candidate_name": "v358 v351-reset + taxonomy support-discipline + live equivalence only", "run_id": "e", "seed": 505, "score": 38.7409, "family": "v351_phase4_live_equivalence_support_discipline_retrieval", "flags": ["direct_support_hygiene", "code_low_rank"]},
        ]
        stop_notice = {"reason": "adaptive_plateau", "mode": "v358", "completed_runs": len(state["history"]), "incumbent_name": state["incumbent_name"], "incumbent_score": state["incumbent_score"]}
        followup = recommend_followup_mode("v358", state, stop_notice)
        self.assertEqual(followup["next_mode"], "v359")
        self.assertAlmostEqual(followup["evidence"]["control_score"], 38.7409, places=6)
        self.assertAlmostEqual(followup["evidence"]["support_slate_score"], 38.8565, places=6)
        self.assertAlmostEqual(followup["evidence"]["v351_frontier_score"], 38.85648351659378, places=6)
        self.assertEqual(
            followup["evidence"]["remaining_strict_failures"],
            [
                "objective_supported_direct_rate ~0.33 below 0.375 target despite clean abstention",
                "code/query effective rank remains compressed even with vicreg and rank_reg",
                "ordering: no ordered-support signal taught anywhere in the v358 family",
            ],
        )

