    def test_aggregate_eval_summaries_tracks_replica_metadata(self) -> None:
        from experiments.run_strict_eval_autoresearch import _aggregate_eval_summaries

        summary = _aggregate_eval_summaries(
            [
                {
                    "strict_status": "❌ FAIL",
                    "answer_score": 10.0,
                    "avg_known_similarity": 0.70,
                    "avg_known_exact_similarity": 0.71,
                    "avg_known_paraphrase_similarity": 0.69,
                    "synthesis_similarity": 0.68,
                    "avg_known_margin": 0.0002,
                    "ignorance_gap": 0.12,
                    "avg_ood_confidence": 0.91,
                    "strict_failures": ["q1"],
                    "query_diagnostics": {"avg_offdiag_similarity": 0.98, "participation_ratio_fraction": 0.02},
                    "code_diagnostics": {"avg_offdiag_similarity": 0.95, "participation_ratio_fraction": 0.11},
                },
                {
                    "strict_status": "❌ FAIL",
                    "answer_score": 8.0,
                    "avg_known_similarity": 0.72,
                    "avg_known_exact_similarity": 0.73,
                    "avg_known_paraphrase_similarity": 0.71,
                    "synthesis_similarity": 0.70,
                    "avg_known_margin": 0.0004,
                    "ignorance_gap": 0.14,
                    "avg_ood_confidence": 0.89,
                    "strict_failures": ["q2"],
                    "query_diagnostics": {"avg_offdiag_similarity": 0.96, "participation_ratio_fraction": 0.04},
                    "code_diagnostics": {"avg_offdiag_similarity": 0.94, "participation_ratio_fraction": 0.13},
                },
            ]
        )

        self.assertAlmostEqual(summary["answer_score"], 9.0)
        self.assertAlmostEqual(summary["avg_known_exact_similarity"], 0.72)
        self.assertAlmostEqual(summary["query_diagnostics"]["participation_ratio_fraction"], 0.03)
        self.assertEqual(summary["replica_count"], 2)
        self.assertEqual(summary["strict_status"], "❌ FAIL")
        self.assertEqual(summary["strict_failures"], ["q1", "q2"])

