        state["history"] = [
            {"candidate_name": "v193 clean v192 paraphrase-quorum control", "run_id": "a", "seed": 501, "score": 2.3013, "family": "quorum_promoted_contract_aware_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small"]},
            {"candidate_name": "v193 clean v192 paraphrase-quorum + support-pref pairwise coverage", "run_id": "b", "seed": 502, "score": 4.2299, "family": "quorum_promoted_contract_aware_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small"]},
            {"candidate_name": "v193 clean v192 paraphrase-quorum + support-pref multistep floor", "run_id": "c", "seed": 503, "score": 4.2724, "family": "quorum_promoted_contract_aware_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small"]},
            {"candidate_name": "v193 clean v192 paraphrase-quorum + hard multistep floor", "run_id": "d", "seed": 504, "score": 4.3654, "family": "quorum_promoted_contract_aware_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small"]},
            {"candidate_name": "v193 clean v192 paraphrase-quorum + code-pref tie-break", "run_id": "e", "seed": 505, "score": 1.7565, "family": "quorum_promoted_contract_aware_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small"]},
        ]
        stop_notice = {"reason": "no_candidate_available", "mode": "v193", "completed_runs": len(state["history"]), "incumbent_name": state["incumbent_name"], "incumbent_score": 4.3654}
