        self.assertAlmostEqual(followup["evidence"]["support_pref_multistep_floor_score"], 4.2724)
        self.assertAlmostEqual(followup["evidence"]["hard_multistep_floor_score"], 4.3654)
        self.assertAlmostEqual(followup["evidence"]["code_pref_tie_break_score"], 1.7565)

