            {"candidate_name": "v202 clean v178 citecheck pairwise + parafence stability", "run_id": "b", "seed": 502, "score": 0.3875, "family": "clean_support_aware_parafence_safe_expand_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small", "synthesis_weak"]},
            {"candidate_name": "v202 clean v178 citecheck pairwise + low-margin safe expand", "run_id": "c", "seed": 503, "score": 1.5910, "family": "clean_support_aware_parafence_safe_expand_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small", "synthesis_weak"]},
            {"candidate_name": "v202 clean v178 citecheck pairwise + parafence stability + safe expand", "run_id": "d", "seed": 504, "score": 1.8351, "family": "clean_support_aware_parafence_safe_expand_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small"]},
            {"candidate_name": "v202 clean v178 citecheck pairwise + deterministic paraphrase quorum", "run_id": "e", "seed": 505, "score": 3.6525, "family": "clean_support_aware_parafence_safe_expand_verifier", "flags": ["query_collapse", "code_low_rank", "ood_overconfident", "ignorance_gap_small", "margin_too_small"]},
