class StrictAutoresearchTrainFailureHandlingTests(unittest.TestCase):
    def test_record_result_does_not_suppress_family_on_train_failed(self) -> None:
        from experiments.run_strict_eval_autoresearch import record_result
        from research.strict_eval_search_space import strict_v293_candidate_library

        state = {
            "mode": "v293",
            "incumbent_name": "v293 promoted hybrid global + facets control",
            "incumbent_score": -999.0,
            "suppressed_families": [],
            "history": [],
            "completed_runs": 0,
        }
        candidate = next(
            c
            for c in strict_v293_candidate_library()
            if c.name == "v293 promoted hybrid global + facets + more facets"
        )
        summary = {
            "run_status": "train_failed",
            "strict_status": "train_failed",
            "avg_known_similarity": 0.0,
            "avg_known_exact_similarity": 0.0,
            "avg_known_paraphrase_similarity": 0.0,
            "synthesis_similarity": 0.0,
            "avg_known_margin": 0.0,
            "ignorance_gap": 0.0,
            "avg_ood_confidence": 1.0,
            "strict_failures": ["train_failed"],
            "query_diagnostics": {"avg_offdiag_similarity": 1.0, "participation_ratio_fraction": 0.0},
            "code_diagnostics": {"avg_offdiag_similarity": 1.0, "participation_ratio_fraction": 0.0},
        }

        entry = record_result(state, candidate, 502, summary)
        self.assertEqual(entry["run_status"], "train_failed")
        self.assertEqual(entry["primary_failure_mode"], "train_failed")
        self.assertEqual(state["suppressed_families"], [])


if __name__ == "__main__":
    unittest.main()
